form:Form.form:Scripts:
		function ObjetoActualizador() 
{
	this.processResult = function(strResult)
	{  
		Ctrl('main').DoEvent("CERRAR");
	}
}

function SetFecha()
{
	if(Ctrl('oi_error').GetXValue() != "")
	{
		np = new NomadProxy("", ut);
		nSQL = np.SQLService();       
		var FechaVenc = nSQL.GetOBJ(Ctrl("main").getResource("GetFechaVencimiento"), "<PARAM oi_error=\""+Ctrl('oi_error').GetXValue()+"\" />"); 	
		Ctrl('f_estim_implem').SetXValue(FechaVenc.f_vencimiento);
	}
	else
		Ctrl('f_estim_implem').SetXValue('');		 


}

function onLoad()
{
	if (Ctrl('main').GetMode()=='NEW' || Ctrl('main').GetMode()=='DUP')
  {
  	Ctrl('f_solicitud').SetTypedValue(new Date());
    //Ctrl('c_solicitud').SetXValue(Ctrl('f_solicitud').TypedValue().getFullYear()+' '+'asdasd');
		Ctrl('c_estado').SetXValue(1);
		Ctrl('oi_error').SetXValue(3);
		Ctrl('c_clasificacion').SetXValue(5);
		Ctrl('oi_unidad_tiempo_aux').SetXValue(2);
		Ctrl('banEstadoCerrRech').SetXValue(0);
		Ctrl('f_inicio').SetTypedValue(new Date());
		if (Ctrl('f_estim_implem').GetXValue()!="")
		{ 

			Ctrl('f_fin_est').SetXValue(Ctrl('f_estim_implem').GetXValue());
		}

  }

  else if (Ctrl('main').GetMode()=='EDIT')
  {
  	if((Ctrl('c_estado').GetXValue()>=5) && (Ctrl('c_estado').GetXValue()<=7))
  	{
  		CtrlEnabled("c_estado", false);
  		CtrlEnabled("f_estado", false);
  	}  

  }

  if (Ctrl('main').GetMode() == 'LIST_EDIT' || Ctrl('main').GetMode() == 'LIST')
	{ 
		Ctrl("listarr").DelAllRow();
		Ctrl("LIST").Refresh();
	}
}


function cambiarFeEstado()
{
	Ctrl('f_estado').SetTypedValue(new Date());

	if((Ctrl('c_estado').GetXValue()>=5) && (Ctrl('c_estado').GetXValue()<=7))
		Ctrl('banEstadoCerrRech').SetXValue(1);
	else
		Ctrl('banEstadoCerrRech').SetXValue(0);
}

function cambiarFeImplem()
{
	Ctrl('f_implem').SetTypedValue(new Date());  

}

function trim(cadena)
{

    for(i=0; i<cadena.length; i++)
    {
        if(cadena.charAt(i)==" ")
        {
            cad1=cadena.substring(0, i);

        		cad2=cad1+cadena.substring(i+1,cadena.length);		
        }
    }

    return cad2;
}

function IsNumeric(sText)
{
   var ValidChars = "0123456789.";
   var IsNumber=true;
   var Char;


   for (i = 0; i < sText.length && IsNumber == true; i++) 
   { 
      Char = sText.charAt(i); 
      if (ValidChars.indexOf(Char) == -1) 
      {
      	 IsNumber = false;
      }
   }
   return IsNumber;

}

function validar(OBJCTRL)
{
	if(!IsNumeric(trim(OBJCTRL.GetCValue())))
	{
		//alert('Codigo de Solicitud Incorrecto!');
		OBJCTRL.SetError('El Codigo de Solicitud no es numerico');
		return false;
	}

	return true;
	//Ctrl('main').DoEvent('SAVE');

}  

function oi_proyectoReport()
{
	this.processResult = function(XML)
	{                 
		var myRESULT=new NomadXML(XML);
		Ctrl("oi_proyecto_C" ).SetXValue(myRESULT.GetAttr("oi_proyecto"));
		Ctrl("oi_pry_imputa_C" ).SetXValue(myRESULT.GetAttr("oi_proyecto"));
	}
}

function Clearoi_proyecto()
{
	Ctrl("oi_proyecto_C").SetXValue("");
}

function Findoi_proyecto()
{                    
	openNewFlowWait("NucleusProject.Base.Project.Proyectos.PROYECTO.guia.flow","HELP",'<DATA oi_proyecto="'+Ctrl("oi_proyecto_C").GetXValue()+'" ESTADOS="ITL" />',new oi_proyectoReport(),"S");
}

function oi_pry_imputaReport()
{
	this.processResult = function(XML)
	{                 
		var myRESULT=new NomadXML(XML);
		Ctrl("oi_pry_imputa_C" ).SetXValue(myRESULT.GetAttr("oi_proyecto"));
	}
}

function Clearoi_pry_imputa()
{
	Ctrl("oi_pry_imputa_C").SetXValue("");
}

function Findoi_pry_imputa()
{                    
	openNewFlowWait("NucleusProject.Base.Project.Proyectos.PROYECTO.guia.flow","HELP",'<DATA oi_proyecto="'+Ctrl("oi_pry_imputa_C").GetXValue()+'" ESTADOS="IT" />',new oi_pry_imputaReport(),"S");
}

function LimpiarNombreSolicitud(nombre)
{                                  
	nombre = nombre.replace(/[.#*+?^${}()/|[\]\\]/g, ' ')    
	Ctrl('d_solicitud').SetXValue(nombre);
}
function validarTarea()
{  
	LimpiarNombreSolicitud(Ctrl('d_solicitud').GetXValue());
 if(validaCentroCosto())
 {

	//solicita confirmacion en caso de rechazar/cerrar la solicitud
  if((Ctrl('c_estado').GetXValue()>=5) && (Ctrl('c_estado').GetXValue()<=7) && (Ctrl('banEstadoCerrRech').GetXValue()==1))
	{ 
		var r=confirm("Esta seguro de cerrar / rechazar esta solicitud?");

		if(r!=true)
			return false;
	}

	//Validar Campos de la Tarea 
	if(Ctrl('main').GetMode()=='NEW' || Ctrl('main').GetMode()=='DUP' )
	{ 
	  //Validar fecha inicio y fin
		if(Ctrl("f_fin_est").GetXValue() != "")
 		{
 			if(Ctrl("f_inicio").GetXValue() > Ctrl("f_fin_est").GetXValue())
 			{   
 				alert("La fecha de inicio debe ser igual o posterior a la fecha de fin estimada"); 
 		  	return false;
 			}
 		} 

		if((Ctrl('oi_proyecto_C').GetXValue()=='') &&
					(Ctrl('oi_pry_imputa_C').GetXValue()=='') &&
		 			(Ctrl('e_estimado_aux').GetXValue()=='') &&
		 					(Ctrl('oi_unidad_tiempo_aux').GetXValue()=='') && 
		 							(Ctrl('c_clasificacion').GetXValue()=='') &&
		 								(Ctrl('f_inicio').GetXValue()=='') &&
		 									(Ctrl('f_fin_est').GetXValue()=='')
		 	)
		{         
			//solicitud sin tarea
			return true;
		}		

		if((Ctrl('oi_proyecto_C').GetXValue()=='') ||
						(Ctrl('oi_pry_imputa_C').GetXValue()=='') ||
		 					(Ctrl('e_estimado_aux').GetXValue()=='') ||
		 						(Ctrl('oi_unidad_tiempo_aux').GetXValue()=='') || 
		 							(Ctrl('c_clasificacion').GetXValue()=='') ||
		 								  (Ctrl('f_inicio').GetXValue()=='') ||
		 								  	(Ctrl('f_fin_est').GetXValue()=='')
		 	)                    
		{         
			alert('Hay datos de la Tarea Incompletos.');
			return false;
		}
		else
		{
			if(Ctrl('oi_recurso').GetXValue()=='')
			{
				alert('Debe completar el campo Responsable.');
				return false;
			}
		}
	}

  np = new NomadProxy("", ut);
	nSQL = np.SQLService();       
	var requerido = nSQL.GetOBJ(Ctrl("main").getResource("RequiereVencimiento"), "<PARAM oi_error=\""+Ctrl('oi_error').GetXValue()+"\" />"); 	
	if((requerido.c_req_venc == "2") && (Ctrl('f_estim_implem').GetXValue() == ""))
	{
		alert('Se necesita completar la fecha estimada de implementación.');
		return false;
	}

	return true;
} }

function unmark_list()
{
	Ctrl("listarr").DelAllRow();
	Ctrl("LIST").Refresh();
}

function mark_list()
{
	Ctrl("listarr").DelAllRow();     
	for (var t=0; t<Ctrl("LIST").RowsCount(); t++)
		Ctrl("listarr").AddRow().SetAttr("id", Ctrl("LIST").shownRegs[t].attributes.getNamedItem("id").value);

	Ctrl("LIST").Refresh();
}

function ShowSel() 
{
	var DOCRS, XMLLista;
	DOCRS = Ctrl("main").GetLastDoc("RS").childNodes;
	XMLLista = new NomadXML("ROWS");      

	for (var i=0; i < DOCRS.length; i++) 
	{
		if (Ctrl("listarr").GetRowByAttr("id", DOCRS[i].getAttribute("id")) != null) 
			XMLLista.AddText(ELE2String(DOCRS[i]));
	}

	Ctrl('LIST').processResult(XMLLista.ToString());
}

function ShowAll() 
{
	Ctrl('LIST').processResult(ELE2String(Ctrl("main").GetLastDoc("RS")));	
}

function CERRAR()
{
	var DOCRS, XMLLista;
	DOCRS = Ctrl("main").GetLastDoc("RS").childNodes;
	XMLLista = new NomadXML("ROWS");
	var flag="0";

	for (var i=0; i < DOCRS.length; i++)
	{
		if (Ctrl("listarr").GetRowByAttr("id", DOCRS[i].getAttribute("id")) != null && (DOCRS[i].getAttribute("c_estado") != "5" && DOCRS[i].getAttribute("c_estado") != "7"))
		{
			XMLLista.AddText(ELE2String(DOCRS[i]));
			flag="1";
		}
	}

	if (flag=="1")
		openNewFlow("NucleusProject.Base.Project.Solicitudes.CAMBIOS.guia.flow","CERRAR",XMLLista.ToString(),new ObjetoActualizador(),"L");
	else
		alert("Debe seleccionar al menos una solicitud con estado distinto a CERRADO o RECHAZADO.");
}

function CAMBIO()
{
	var DOCRS, XMLLista;
	DOCRS = Ctrl("main").GetLastDoc("RS").childNodes;
	XMLLista = new NomadXML("ROWS");      

	for (var i=0; i < DOCRS.length; i++) 
	{
		if (Ctrl("listarr").GetRowByAttr("id", DOCRS[i].getAttribute("id")) != null) 
		{
			Ctrl("main").DoEvent("CAMBIO");
			return true;
		}

	}

	alert("Debe seleccionar una solicitud para cambiar el responsable");
}      

function DERIVAR()
{
	var DOCRS, XMLLista;
	DOCRS = Ctrl("main").GetLastDoc("RS").childNodes;
	XMLLista = new NomadXML("ROWS");
	var flag="0";

	for (var i=0; i < DOCRS.length; i++)
	{
		if (Ctrl("listarr").GetRowByAttr("id", DOCRS[i].getAttribute("id")) != null && (DOCRS[i].getAttribute("c_estado") == "1" || DOCRS[i].getAttribute("c_estado") == "8"))
		{
			XMLLista.AddText(ELE2String(DOCRS[i]));
			flag="1";
		}
	}

	if (flag=="1")
		openNewFlow("NucleusProject.Base.Project.Solicitudes.CAMBIOS.guia.flow","DERIVAR",XMLLista.ToString(),new ObjetoActualizador(),"L");
	else
		alert("Debe seleccionar al menos una solicitud con estado PENDIENTE o TRABAJANDO.");
}

function RECHAZAR()
{
	var DOCRS, XMLLista;
	DOCRS = Ctrl("main").GetLastDoc("RS").childNodes;
	XMLLista = new NomadXML("ROWS");
	var flag="0";

	for (var i=0; i < DOCRS.length; i++)
	{
		if (Ctrl("listarr").GetRowByAttr("id", DOCRS[i].getAttribute("id")) != null && (DOCRS[i].getAttribute("c_estado") == "1" || DOCRS[i].getAttribute("c_estado") == "4"))
		{
			XMLLista.AddText(ELE2String(DOCRS[i]));
			flag="1";
		}
	}

	if (flag=="1")
		openNewFlow("NucleusProject.Base.Project.Solicitudes.CAMBIOS.guia.flow","RECHAZAR",XMLLista.ToString(),new ObjetoActualizador(),"L");
	else
		alert("Debe seleccionar al menos una solicitud con estado PENDIENTE o DERIVADO A CLIENTES.");
}

