function REPORTE_TAREAS()
{     

	var id;
	var MyRetVal=new NomadXML();
	if(Ctrl('hid_oi_solicitud').GetXValue() != "")
		id = Ctrl('hid_oi_solicitud').GetXValue();
	else
		id=0;  


	if(Ctrl('main').GetMode() == "LIST")
		id = Ctrl("LIST").GetSelectAttrValue("id");   


	if(Ctrl('main').GetMode() == "SHOW" || Ctrl('main').GetMode() == "LIST")
		openNewFlow("NucleusProject.Base.Project.Solicitudes.SOLICITUD_DETALLES.flow","REPORTE_TAREAS",'<DATOS oi_solicitud="'+id+'" />',MyRetVal,"L");
}

function validaCentroCosto()
{

 if(Ctrl('oi_contacto').GetXValue() != "")
	{
		np = new NomadProxy("", ut);
		nSQL = np.SQLService();       
		var Cliente = nSQL.GetOBJ(Ctrl("main").getResource("GetClienteDeContacto"), "<PARAM oi_contacto=\""+Ctrl('oi_contacto').GetXValue()+"\" />"); 	

		if (Cliente.oi_cliente == 1 && (Ctrl('oi_centro_costo').GetXValue() == "")) 
		{
		  alert('El valor es requerido'); 
		  Ctrl('oi_centro_costo').SetFocus();
		  return false;
		}
		else
		  return true;
	}
  else
  return true;	
}

function DUP()
{
	CALL_MODE("DUP");
}

function CALL_MODE(mode)
{ 
	var MyRetVal=new NomadXML();                                     
	switch (mode)
	{ 
		case "DUP": 		  					
			openNewFlow("NucleusProject.Base.Project.Solicitudes.flow",mode,'<DATA oi_solicitud="'+Ctrl('hid_oi_solicitud').GetXValue()+'" />',MyRetVal,"L");
		break;       

		default:
			alert("Lo siento mucho...\r\nNo esta Implementado!")
		break;
	}
}
